def b64_encode(s):
    return base64.urlsafe_b64encode(s).strip(b"=")


def b64_decode(s):
    pad = b"=" * (-len(s) % 4)
    return base64.urlsafe_b64decode(s + pad)


# RemovedInDjango70Warning: algorithm="sha256"
def base64_hmac(salt, value, key, algorithm=None):
    if algorithm is None:
        warnings.warn(
            "The default argument for algorithm in base64_hmac() will change "
            "from 'sha1' to 'sha256' in Django 7.0. Pass an explicit "
            "algorithm to silence this warning.",
            category=RemovedInDjango70Warning,
            skip_file_prefixes=django_file_prefixes(),
        )
        algorithm = "sha1"
    return b64_encode(
        salted_hmac(salt, value, key, algorithm=algorithm).digest()
    ).decode()


def _cookie_signer_key(key):
    # SECRET_KEYS items may be str or bytes.
    return b"django.http.cookies" + force_bytes(key)


def _cookie_signer_salt(cookie_name, salt=""):
    # Prefix the salt length so (cookie_name, salt) pairs can't collide.
    return f"django.http.cookies.v2:{len(salt)}:{salt}{cookie_name}"

from dojo.tools.aws_prowler_v3plus.prowler_v3 import AWSProwlerV3Parser
from dojo.tools.aws_prowler_v3plus.prowler_v4 import AWSProwlerV4Parser


class AWSProwlerV3plusParser:
    SCAN_TYPE = ["AWS Prowler V3"]

    def get_scan_types(self):
        return AWSProwlerV3plusParser.SCAN_TYPE

    def get_label_for_scan_types(self, scan_type):
        return AWSProwlerV3plusParser.SCAN_TYPE[0]

    def get_description_for_scan_types(self, scan_type):
        return "Exports from AWS Prowler v3 in JSON format or from Prowler v4 in OCSF-JSON format."

    def get_findings(self, file, test):
        if file.name.lower().endswith(".ocsf.json"):
            return AWSProwlerV4Parser().process_ocsf_json(file, test)
        if file.name.lower().endswith(".json"):
            return AWSProwlerV3Parser().process_json(file, test)
        msg = "Unknown file format"
        raise ValueError(msg)

from django.contrib.auth.hashers import UNUSABLE_PASSWORD_PREFIX, identify_hasher
from django.template import Library
from django.utils.html import format_html, format_html_join
from django.utils.translation import gettext

register = Library()


@register.simple_tag
def render_password_as_hash(value):
    if not value or value.startswith(UNUSABLE_PASSWORD_PREFIX):
        return format_html("<p><strong>{}</strong></p>", gettext("No password set."))
    try:
        hasher = identify_hasher(value)
        hashed_summary = hasher.safe_summary(value)
    except ValueError:
        return format_html(
            "<p><strong>{}</strong></p>",
            gettext("Invalid password format or unknown hashing algorithm."),
        )
    items = [(gettext(key), val) for key, val in hashed_summary.items()]
    return format_html(
        "<p>{}</p>",
        format_html_join(" ", "<strong>{}</strong>: <bdi>{}</bdi>", items),
    )

import hashlib
import re
from functools import lru_cache

from django.template.loader import render_to_string
from django.urls import reverse

from wagtail import hooks

icon_comment_pattern = re.compile(r"<!--.*?-->", re.DOTALL)


@lru_cache(maxsize=None)
def get_icons():
    all_icons = []
    for fn in hooks.get_hooks("register_icons"):
        all_icons = fn(all_icons)
    all_icons = sorted(all_icons)
    combined_icon_markup = ""
    for icon in all_icons:
        symbol = (
            render_to_string(icon)
            .replace('xmlns="http://www.w3.org/2000/svg"', "")
            .replace("svg", "symbol")
        )
        symbol = icon_comment_pattern.sub("", symbol)
        combined_icon_markup += symbol

    return render_to_string(
        "wagtailadmin/shared/icons.html", {"icons": combined_icon_markup}
    )


@lru_cache(maxsize=None)
def get_icon_sprite_hash():
    return hashlib.sha1(get_icons().encode()).hexdigest()[:8]


def get_icon_sprite_url():
    return reverse("wagtailadmin_sprite") + f"?h={get_icon_sprite_hash()}"

#!/usr/bin/env python
import os
import sys

if __name__ == "__main__":
    environment = "production"
    if os.environ.get("DEBUG", "0") == "1":
        environment = "development"

    try:
        command = sys.argv[1]
    except IndexError:
        command = "help"

    do_not_collect_coverage = os.environ.get("NO_COVERAGE") is not None
    running_tests = command == "test"
    if running_tests:
        environment = "test"
    if running_tests and not do_not_collect_coverage:
        from coverage import Coverage

        cov = Coverage()
        cov.erase()
        cov.start()

    from django.core.management import execute_from_command_line

    os.environ.setdefault(
        "DJANGO_SETTINGS_MODULE", f"librephotos.settings.{environment}"
    )
    execute_from_command_line(sys.argv)

    if running_tests and not do_not_collect_coverage:
        cov.stop()
        cov.save()
        cov.html_report()
        covered = cov.report()

import base64
import io

from django import forms
from django.utils.encoding import force_text


class Base64ImageWidget(forms.widgets.Widget):
    template_name = 'converter/forms/widgets/base64_image.html'

    def format_value(self, value):
        if value == '' or value is None:
            return None
        else:
            with io.BytesIO() as output:
                value.save(output, format='PNG')
                image = output.getvalue()
                url = 'data:image/png;charset=utf-8;base64,{}'.format(
                    force_text(base64.b64encode(image))
                )

                return url


class ImageWidget(forms.widgets.Widget):
