    def format_value(self, value):
        if value == '' or value is None:
            return None
        return value

import re


class UniformTrivyVulnID:
    def return_uniformed_vulnid(self, vulnid):
        if vulnid is None:
            return vulnid
        if "cve" in vulnid.lower():
            return vulnid
        if "khv" in vulnid.lower():
            temp = re.compile(r"([a-zA-Z-_]+)([0-9]+)")
            number = str(temp.match(vulnid).groups()[1]).zfill(3)
            avd_category = str(temp.match(vulnid.lower()).groups()[0])
            return avd_category.upper() + number
        if "ksv" in vulnid.lower() or "kcv" in vulnid.lower():
            temp = re.compile(r"([a-zA-Z-_]+)([0-9]+)")
            number = str(temp.match(vulnid).groups()[1]).zfill(4)
            avd_category = str(temp.match(vulnid.lower().replace("_", "").replace("-", "")).groups()[0].replace("avd", ""))
            return "AVD-" + avd_category.upper() + "-" + number
        return vulnid

class RegisterLookupMixin:
    class_lookups: ClassVar[dict[str, Any]]
    lookup_name: str
    @classmethod
    def get_class_lookups(cls) -> dict[str, Any]: ...
    def get_instance_lookups(self) -> dict[str, Any]: ...
    def get_lookups(self) -> dict[str, Any]: ...
    def get_lookup(self, lookup_name: str) -> type[Lookup] | None: ...
    def get_transform(self, lookup_name: str) -> type[Transform] | None: ...
    @staticmethod
    def merge_dicts(dicts: Iterable[dict[str, Any]]) -> dict[str, Any]: ...
    @classmethod
    def register_class_lookup(cls, lookup: _R, lookup_name: str | None = None) -> _R: ...
    def register_instance_lookup(self, lookup: _R, lookup_name: str | None = None) -> _R: ...
    @classmethod
    def register_lookup(cls, lookup: _R, lookup_name: str | None = None) -> _R: ...
    @classmethod
    def _unregister_class_lookup(cls, lookup: type[Lookup], lookup_name: str | None = None) -> None: ...
    def _unregister_instance_lookup(self, lookup: type[Lookup], lookup_name: str | None = None) -> None: ...
    @classmethod
    def _unregister_lookup(cls, lookup: type[Lookup], lookup_name: str | None = None) -> None: ...
